code = """import json
import re

# Get the businesses that accept credit cards from storage
businesses = [
    {"_id": "6859a000fe8b31cd7362e2ab", "business_id": "businessid_49", "name": "Steps to Learning Montessori Preschool", "description": "Located at 6901 Phelps Rd in Goleta, CA, this facility offers a nurturing environment for young learners, providing a range of services in Education, Elementary Schools, Child Care & Day Care, Local Services, Preschools, and Montessori Schools."},
    {"_id": "6859a000fe8b31cd7362e2ac", "business_id": "businessid_47", "name": "Breeze Blow Dry Bar", "description": "Located at 9916 Clayton Rd in St. Louis, MO, this establishment offers a wide range of services, including Hair Salons, Beauty & Spas, Hair Stylists, Skin Care, Blow Dry/Out Services, and Makeup Artists."},
    {"_id": "6859a000fe8b31cd7362e2ad", "business_id": "businessid_88", "name": "Impact Guns", "description": "Located at 11655 W Executive Dr in Boise, ID, this facility offers enthusiasts a premier destination for Gun/Rifle Ranges, Active Life."},
    {"_id": "6859a000fe8b31cd7362e2af", "business_id": "businessid_33", "name": "J&Q Nails", "description": "Located at 9655 E US Hwy 36, Unit H in Avon, IN, this establishment offers a range of services including Nail Salons, Hair Removal, Beauty & Spas, and Waxing."},
    {"_id": "6859a000fe8b31cd7362e2b1", "business_id": "businessid_92", "name": "Luminosity", "description": "Located at 690 W Dekalb Pike in King of Prussia, PA, this business offers a diverse range of services and products in the fields of Cosmetics & Beauty Supply, Cosmetic Dentists, Tanning, Teeth Whitening, Beauty & Spas, Dentists, Shopping, Blow Dry/Out Services, Health & Medical, Spray Tanning, and Hair Salons."}
]

# Extract categories from descriptions
categories = []
category_map = {}  # Map category to business_ids

for biz in businesses:
    description = biz["description"]
    # Extract categories from description
    # Categories are usually listed after "services in", "includes", "including", or similar phrases
    if "services in" in description:
        parts = description.split("services in")
    elif "including" in description:
        parts = description.split("including")
    elif "in the fields of" in description:
        parts = description.split("in the fields of")
    else:
        continue
        
    if len(parts) > 1:
        category_text = parts[1]
        # Remove the period at the end
        category_text = category_text.rstrip(".")
        # Split by commas or "and"
        cats = re.split(r',|\sand\s', category_text)
        
        for cat in cats:
            cat = cat.strip()
            if cat:
                categories.append(cat)
                if cat not in category_map:
                    category_map[cat] = []
                category_map[cat].append(biz["business_id"])

# Count category occurrences
category_counts = {}
for cat in categories:
    category_counts[cat] = category_counts.get(cat, 0) + 1

print("__RESULT__:")
print(json.dumps({
    "businesses": businesses,
    "category_counts": category_counts,
    "category_map": category_map
}))"""

